parameters.jsCode:
const text = $json.output || "";

// find JSON block inside response
const match = text.match(/\{[\s\S]*\}/);

if (match) {
  try {
    const data = JSON.parse(match[0]);

    return [
      {
        json: {
          parsed: true,
          ...data
        }
      }
    ];
  } catch (e) {}
}

// normal AI text reply
return [
  {
    json: {
      parsed: false,
      output: text
    }
  }
];

const text = $json.output || "";

// 🧠 Try extracting JSON safely
let jsonMatch = text.match(/\{[\s\S]*?\}/);

if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);

    return [
      {
        json: {
          parsed: true,
          status: parsed.status || "",
          name: parsed.name || "",
          email: parsed.email || "",
          service: parsed.service || "",
          date: parsed.date || "",
          time: parsed.time || "",
          message: parsed.message || "",
        }
      }
    ];
  } catch (err) {
    // JSON found but invalid → treat as normal reply
  }
}

// 🗣️ Normal conversational reply (Hindi text)
return [
  {
    json: {
      parsed: false,
      output: text.trim()
    }
  }
];

